        WHICH_MEMORY_WILL_YOU_HAVE_RECALLED_NONE_EYES                        = 7272,  -- Which memory will you have recalled? None. Eyes on You(pt.1). Eyes on You(pt.2). Oshasha Violation(pt.1). Oshasha Violation(pt.2). Phantasmic Heroes.
        WHICH_MEMORY_WILL_YOU_HAVE_RECALLED_NONE                             = 7273,  -- Which memory will you have recalled? None.
